import React, { useEffect, useState } from 'react';
import { getApiUrl } from '../config/api';
import axios from 'axios';
import toast from 'react-hot-toast';

interface Query {
  id: string;
  customer_name?: string;
  first_name?: string;
  last_name?: string;
  email?: string;
  phone?: string;
  subject?: string;
  message?: string;
  status: string;
  created_at_formatted?: string;
  admin_response?: string;
  response_date_formatted?: string;
}

const TABS = [
  { id: 'all', label: 'All' },
  { id: 'pending', label: 'Pending' },
  { id: 'responded', label: 'Responded' },
];

const AdminContactQueries: React.FC = () => {
  const [queries, setQueries] = useState<Query[]>([]);
  const [statusCounts, setStatusCounts] = useState<{ [key: string]: number }>({});
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('all');
  const [selectedQuery, setSelectedQuery] = useState<Query | null>(null);
  const [showDetailsModal, setShowDetailsModal] = useState(false);
  const [showRespondModal, setShowRespondModal] = useState(false);
  const [responseText, setResponseText] = useState('');
  const [responding, setResponding] = useState(false);

  const fetchQueries = async () => {
    setLoading(true);
    try {
      const sessionId = localStorage.getItem('sessionId');
      const res = await axios.get(getApiUrl('admin_contact_queries.php'), {
        headers: { 'Session-ID': sessionId || '' },
      });
      if (res.data.status === 'success') {
        setQueries(res.data.queries || []);
        setStatusCounts(res.data.status_counts || {});
      } else {
        toast.error(res.data.message || 'Failed to fetch queries');
      }
    } catch (e) {
      toast.error('Network error');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchQueries();
  }, []);

  const filteredQueries = queries.filter(q => {
    if (activeTab === 'all') return true;
    return q.status === activeTab;
  });

  const openDetails = (query: Query) => {
    setSelectedQuery(query);
    setShowDetailsModal(true);
  };

  const openRespond = (query: Query) => {
    setSelectedQuery(query);
    setResponseText('');
    setShowRespondModal(true);
  };

  const handleRespond = async () => {
    if (!selectedQuery || responseText.trim().length < 10) {
      toast.error('Response must be at least 10 characters');
      return;
    }
    setResponding(true);
    try {
      const sessionId = localStorage.getItem('sessionId');
      const res = await axios.post(getApiUrl('admin_contact_queries.php'), {
        query_id: selectedQuery.id,
        response: responseText.trim(),
        status: 'responded',
      }, {
        headers: { 'Session-ID': sessionId || '', 'Content-Type': 'application/json' },
      });
      if (res.data.status === 'success') {
        toast.success('Response submitted successfully!');
        setShowRespondModal(false);
        fetchQueries();
      } else {
        toast.error(res.data.message || 'Failed to submit response');
      }
    } catch (e) {
      toast.error('Network error');
    } finally {
      setResponding(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto py-8 px-4">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold">Contact Queries</h2>
        <button className="btn btn-primary" onClick={fetchQueries} disabled={loading}>
          {loading ? 'Refreshing...' : 'Refresh'}
        </button>
      </div>
      <div className="flex space-x-4 mb-6">
        {TABS.map(tab => (
          <button
            key={tab.id}
            className={`px-4 py-2 rounded-full font-medium border ${activeTab === tab.id ? 'bg-teal-600 text-white border-teal-600' : 'bg-white text-gray-700 border-gray-300'}`}
            onClick={() => setActiveTab(tab.id)}
          >
            {tab.label} ({statusCounts[tab.id] || (tab.id === 'all' ? queries.length : 0)})
          </button>
        ))}
      </div>
      {loading ? (
        <div className="flex justify-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-teal-600"></div>
        </div>
      ) : filteredQueries.length === 0 ? (
        <div className="text-center text-gray-500 py-12">No queries found.</div>
      ) : (
        <div className="space-y-4">
          {filteredQueries.map(query => (
            <div key={query.id} className="bg-white rounded-lg shadow p-4 flex flex-col md:flex-row md:items-center md:justify-between">
              <div className="flex-1 min-w-0">
                <div className="font-semibold text-gray-900">{query.customer_name || `${query.first_name || ''} ${query.last_name || ''}`}</div>
                <div className="text-xs text-gray-500">{query.email}</div>
                <div className="text-sm text-gray-700 mt-1">{query.subject}</div>
                <div className="text-xs text-gray-400 mt-1">{query.created_at_formatted}</div>
                <div className="text-sm text-gray-600 mt-2 truncate">{query.message}</div>
                {query.admin_response && (
                  <div className="mt-2 p-2 bg-green-50 rounded text-green-700 text-xs">
                    <b>Admin Response:</b> {query.admin_response}
                  </div>
                )}
              </div>
              <div className="flex flex-col space-y-2 mt-4 md:mt-0 md:ml-6">
                <button className="btn btn-outline" onClick={() => openDetails(query)}>View Details</button>
                {query.status === 'pending' && (
                  <button className="btn btn-primary" onClick={() => openRespond(query)}>Respond</button>
                )}
                {query.status === 'pending' && query.phone && (
                  <a href={`tel:${query.phone}`} className="btn btn-secondary">Call</a>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Details Modal */}
      {showDetailsModal && selectedQuery && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-40">
          <div className="bg-white rounded-lg shadow-lg max-w-lg w-full p-6 relative">
            <button className="absolute top-2 right-2 text-gray-400 hover:text-gray-600" onClick={() => setShowDetailsModal(false)}>&times;</button>
            <h3 className="text-xl font-bold mb-4">Query Details</h3>
            <div className="space-y-2">
              <div><b>Customer:</b> {selectedQuery.customer_name || `${selectedQuery.first_name || ''} ${selectedQuery.last_name || ''}`}</div>
              <div><b>Email:</b> {selectedQuery.email}</div>
              <div><b>Phone:</b> {selectedQuery.phone}</div>
              <div><b>Subject:</b> {selectedQuery.subject}</div>
              <div><b>Date:</b> {selectedQuery.created_at_formatted}</div>
              <div><b>Message:</b> {selectedQuery.message}</div>
              {selectedQuery.admin_response && (
                <div className="mt-2 p-2 bg-green-50 rounded text-green-700 text-xs">
                  <b>Admin Response:</b> {selectedQuery.admin_response}
                  {selectedQuery.response_date_formatted && (
                    <div className="text-gray-500 mt-1">Responded: {selectedQuery.response_date_formatted}</div>
                  )}
                </div>
              )}
            </div>
            <div className="flex justify-end mt-6">
              <button className="btn btn-secondary" onClick={() => setShowDetailsModal(false)}>Close</button>
            </div>
          </div>
        </div>
      )}

      {/* Respond Modal */}
      {showRespondModal && selectedQuery && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-40">
          <div className="bg-white rounded-lg shadow-lg max-w-lg w-full p-6 relative">
            <button className="absolute top-2 right-2 text-gray-400 hover:text-gray-600" onClick={() => setShowRespondModal(false)}>&times;</button>
            <h3 className="text-xl font-bold mb-4">Respond to Query</h3>
            <div className="mb-4">
              <textarea
                className="w-full border rounded p-2 min-h-[100px]"
                placeholder="Type your response (at least 10 characters)"
                value={responseText}
                onChange={e => setResponseText(e.target.value)}
                disabled={responding}
              />
            </div>
            <div className="flex justify-end space-x-2">
              <button className="btn btn-secondary" onClick={() => setShowRespondModal(false)} disabled={responding}>Cancel</button>
              <button className="btn btn-primary" onClick={handleRespond} disabled={responding}>
                {responding ? 'Sending...' : 'Send Response'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminContactQueries;
